     1вҶ’/**
     2вҶ’ * Dashboard Types - Centralised Dashboard Components
     3вҶ’ *
     4вҶ’ * TypeScript types for the mileage management dashboard UI.
     5вҶ’ * Based on UX specification MILEAGE-UX-003.
     6вҶ’ */
     7вҶ’
     8вҶ’import type { FleetType, PMLevel, FitnessStatus, TrainStatus } from './train';
     9вҶ’
    10вҶ’// ============================================================================
    11вҶ’// KPI Card Types
    12вҶ’// ============================================================================
    13вҶ’
    14вҶ’/**
    15вҶ’ * KPI card state based on thresholds
    16вҶ’ */
    17вҶ’export type KPIState = 'normal' | 'warning' | 'critical' | 'good';
    18вҶ’
    19вҶ’/**
    20вҶ’ * Trend direction for KPI changes
    21вҶ’ */
    22вҶ’export type TrendDirection = 'up' | 'down' | 'stable';
    23вҶ’
    24вҶ’/**
    25вҶ’ * KPI metric identifier
    26вҶ’ */
    27вҶ’export type KPIMetricId =
    28вҶ’  | 'fleet_availability'
    29вҶ’  | 'pm_compliance'
    30вҶ’  | 'resource_utilisation'
    31вҶ’  | 'cost_variance'
    32вҶ’  | 'mileage_balance'
    33вҶ’  | 'trains_in_service';
    34вҶ’
    35вҶ’/**
    36вҶ’ * KPI card data
    37вҶ’ */
    38вҶ’export interface KPICardData {
    39вҶ’  id: KPIMetricId;
    40вҶ’  label: string;
    41вҶ’  value: number;
    42вҶ’  unit: '%' | 'km' | 'trains' | 'hours' | 'currency';
    43вҶ’  displayValue: string;
    44вҶ’  trend: {
    45вҶ’    direction: TrendDirection;
    46вҶ’    value: number;
    47вҶ’    period: string; // e.g., "vs last month"
    48вҶ’  };
    49вҶ’  state: KPIState;
    50вҶ’  sparklineData?: number[];
    51вҶ’  contextText?: string; // e.g., "121/128 trains available"
    52вҶ’  warningThreshold: number;
    53вҶ’  criticalThreshold: number;
    54вҶ’  invertThresholds?: boolean; // true if lower is worse (e.g., availability)
    55вҶ’}
    56вҶ’
    57вҶ’/**
    58вҶ’ * KPI thresholds configuration
    59вҶ’ */
    60вҶ’export interface KPIThresholds {
    61вҶ’  metricId: KPIMetricId;
    62вҶ’  warningMin?: number;
    63вҶ’  warningMax?: number;
    64вҶ’  criticalMin?: number;
    65вҶ’  criticalMax?: number;
    66вҶ’}
    67вҶ’
    68вҶ’// ============================================================================
    69вҶ’// Fleet Status Types
