   185вҶ’}> = {
   186вҶ’  critical: {
   187вҶ’    bgColor: '#FEF2F2',
   188вҶ’    textColor: '#991B1B',
   189вҶ’    borderColor: '#DC2626',
   190вҶ’    icon: 'error',
   191вҶ’  },
   192вҶ’  warning: {
   193вҶ’    bgColor: '#FFFBEB',
   194вҶ’    textColor: '#854D0E',
   195вҶ’    borderColor: '#F59E0B',
   196вҶ’    icon: 'warning',
   197вҶ’  },
   198вҶ’  info: {
   199вҶ’    bgColor: '#EFF6FF',
   200вҶ’    textColor: '#1E40AF',
   201вҶ’    borderColor: '#3B82F6',
   202вҶ’    icon: 'info',
   203вҶ’  },
   204вҶ’  success: {
   205вҶ’    bgColor: '#F0FDF4',
   206вҶ’    textColor: '#166534',
   207вҶ’    borderColor: '#22C55E',
   208вҶ’    icon: 'check_circle',
   209вҶ’  },
   210вҶ’};
   211вҶ’
   212вҶ’// ============================================================================
   213вҶ’// PM Timeline Types
   214вҶ’// ============================================================================
   215вҶ’
   216вҶ’/**
