/**
 * Man-Hour Projection Chart Types
 *
 * Types for the resource leveling visualization (RFQ Section 8).
 * Supports "Without adjustment" vs "With adjustment" comparison.
 */

/**
 * Time period for chart data points
 */
export interface ChartPeriod {
  year: number;
  month: number; // 1-12
  label: string; // "Jan-26", "Feb-26", etc.
}

/**
 * Single data point for the man-hour projection chart
 */
export interface ManHourDataPoint {
  /** Time period for this data point */
  period: ChartPeriod;

  /** Number of maintenance tasks scheduled in this period */
  taskCount: number;

  /** Predicted workload BEFORE adjustment/leveling (man-hours) */
  predictedWorkload: number;

  /** Adjusted workload AFTER leveling optimization (man-hours) */
  adjustedWorkload: number;

  /** Available man-hours (capacity) for this period */
  availableManHours: number;

  /** Available workforce headcount */
  availableManpower: number;

  /** Gap = available - adjusted (positive = underutilized, negative = overallocated) */
  gap: number;

  /** Utilization percentage = (adjusted / available) * 100 */
  utilizationPercent: number;

  /** Breakdown by fleet type */
  byFleet: {
    KINKI_SHARYO: {
      taskCount: number;
      predictedWorkload: number;
      adjustedWorkload: number;
    };
    ALSTOM: {
      taskCount: number;
      predictedWorkload: number;
      adjustedWorkload: number;
    };
  };
}

/**
 * Gap severity levels for visual indicators
 */
export type GapSeverity = 'comfortable' | 'near_capacity' | 'slight_over' | 'critical_over';

/**
 * Gap thresholds for severity classification
 */
export const GAP_THRESHOLDS = {
  COMFORTABLE: 500,      // Gap > 500: comfortable capacity
  CRITICAL_OVER: -500,   // Gap < -500: critical overallocation
} as const;

/**
 * Classify gap severity based on value
 */
export function classifyGap(gap: number): GapSeverity {
  if (gap > GAP_THRESHOLDS.COMFORTABLE) return 'comfortable';
  if (gap > 0) return 'near_capacity';
  if (gap >= GAP_THRESHOLDS.CRITICAL_OVER) return 'slight_over';
  return 'critical_over';
}

/**
 * Get CSS class/color for gap severity
 */
export function getGapColor(severity: GapSeverity): string {
  switch (severity) {
    case 'comfortable':
      return '#22C55E'; // Green
    case 'near_capacity':
      return '#EAB308'; // Yellow
    case 'slight_over':
      return '#F97316'; // Orange
    case 'critical_over':
      return '#EF4444'; // Red
  }
}

/**
 * Chart comparison mode
 */
export type ComparisonMode = 'without_adjustment' | 'with_adjustment' | 'side_by_side';

/**
 * Fleet filter options
 */
export type FleetFilter = 'ALL' | 'KINKI_SHARYO' | 'ALSTOM';

/**
 * Time range selection
 */
export interface TimeRange {
  start: { year: number; month: number };
  end: { year: number; month: number };
}

/**
 * Chart configuration options
 */
export interface ManHourChartConfig {
  /** Time range to display */
  timeRange: TimeRange;

  /** Comparison mode: show before/after adjustment */
  comparisonMode: ComparisonMode;

  /** Filter by fleet type */
  fleetFilter: FleetFilter;

  /** Show the data table below chart */
  showDataTable: boolean;

  /** Show gap row with color highlighting */
  showGapHighlighting: boolean;

  /** Aggregate data for large time ranges */
  aggregationLevel: 'monthly' | 'quarterly' | 'yearly';

  /** Show predicted workload line (before adjustment) */
  showPredictedLine: boolean;
}

/**
 * Default chart configuration
 */
export const DEFAULT_CHART_CONFIG: ManHourChartConfig = {
  timeRange: {
    start: { year: 2026, month: 1 },
    end: { year: 2026, month: 12 },
  },
  comparisonMode: 'with_adjustment',
  fleetFilter: 'ALL',
  showDataTable: true,
  showGapHighlighting: true,
  aggregationLevel: 'monthly',
  showPredictedLine: true,
};

/**
 * Chart UI state
 */
export interface ManHourChartState {
  /** Chart data points */
  data: ManHourDataPoint[];

  /** Current configuration */
  config: ManHourChartConfig;

  /** Currently hovered data point */
  hoveredPoint: ManHourDataPoint | null;

  /** Currently selected data point */
  selectedPoint: ManHourDataPoint | null;

  /** Loading state */
  isLoading: boolean;

  /** Error message if any */
  error: string | null;
}

/**
 * Initial chart state
 */
export const INITIAL_CHART_STATE: ManHourChartState = {
  data: [],
  config: DEFAULT_CHART_CONFIG,
  hoveredPoint: null,
  selectedPoint: null,
  isLoading: false,
  error: null,
};

/**
 * Tooltip data for hover interaction
 */
export interface ChartTooltipData {
  period: ChartPeriod;
  availability: number;
  adjustedWorkload: number;
  predictedWorkload: number;
  gap: number;
  gapSeverity: GapSeverity;
  utilizationPercent: number;
  taskCount: number;
}

/**
 * Quick range presets for timeline controls
 */
export type QuickRange = '1M' | '3M' | '6M' | '1Y' | '3Y' | 'ALL';

/**
 * Quick range configuration
 */
export const QUICK_RANGE_MONTHS: Record<QuickRange, number> = {
  '1M': 1,
  '3M': 3,
  '6M': 6,
  '1Y': 12,
  '3Y': 36,
  'ALL': 144, // 12 years
};

/**
 * Chart color palette
 */
export const CHART_COLORS = {
  availabilityArea: 'rgba(59, 130, 246, 0.3)',    // Blue with opacity
  capacityLine: '#3B82F6',                         // Solid blue
  adjustedWorkload: '#F97316',                     // Orange
  predictedWorkload: '#6B7280',                    // Gray
  overallocationZone: 'rgba(239, 68, 68, 0.2)',   // Red with opacity
  underallocationZone: 'rgba(34, 197, 94, 0.2)',  // Green with opacity
} as const;

/**
 * Chart dimensions for responsive design
 */
export interface ChartDimensions {
  width: number;
  height: number;
  marginTop: number;
  marginRight: number;
  marginBottom: number;
  marginLeft: number;
}

/**
 * Default dimensions for different screen sizes
 */
export const CHART_DIMENSIONS: Record<'desktop' | 'tablet' | 'mobile', ChartDimensions> = {
  desktop: {
    width: 1200,
    height: 400,
    marginTop: 20,
    marginRight: 30,
    marginBottom: 60,
    marginLeft: 60,
  },
  tablet: {
    width: 768,
    height: 350,
    marginTop: 15,
    marginRight: 20,
    marginBottom: 50,
    marginLeft: 50,
  },
  mobile: {
    width: 375,
    height: 250,
    marginTop: 10,
    marginRight: 10,
    marginBottom: 40,
    marginLeft: 40,
  },
};

/**
 * Data table column definition
 */
export interface DataTableColumn {
  key: keyof ManHourDataPoint | 'gap' | 'period';
  label: string;
  width: number;
  align: 'left' | 'center' | 'right';
  format?: (value: number) => string;
}

/**
 * Default data table columns (matching RFQ Section 8)
 */
export const DEFAULT_TABLE_COLUMNS: DataTableColumn[] = [
  { key: 'period', label: 'Timeline', width: 100, align: 'left' },
  { key: 'taskCount', label: 'No of Task', width: 80, align: 'center' },
  { key: 'predictedWorkload', label: 'Maint. Work', width: 100, align: 'right', format: (v) => v.toLocaleString() },
  { key: 'adjustedWorkload', label: 'Adj. Workload', width: 100, align: 'right', format: (v) => v.toLocaleString() },
  { key: 'availableManHours', label: 'Avail (MH)', width: 100, align: 'right', format: (v) => v.toLocaleString() },
  { key: 'availableManpower', label: 'Manpower', width: 80, align: 'center' },
  { key: 'gap', label: 'Gap (MH)', width: 100, align: 'right', format: (v) => v.toLocaleString() },
];

/**
 * Events emitted by chart component
 */
export interface ChartEvents {
  onPeriodSelect: (period: ChartPeriod) => void;
  onAdjustmentRequest: (period: ChartPeriod) => void;
  onExport: (format: 'csv' | 'excel' | 'pdf') => void;
  onConfigChange: (config: Partial<ManHourChartConfig>) => void;
  onHover: (point: ManHourDataPoint | null) => void;
}

/**
 * Utility: Generate period label from year and month
 */
export function formatPeriodLabel(year: number, month: number): string {
  const months = ['Jan', 'Feb', 'Mar', 'Apr', 'May', 'Jun', 'Jul', 'Aug', 'Sep', 'Oct', 'Nov', 'Dec'];
  const shortYear = String(year).slice(-2);
  return `${months[month - 1]}-${shortYear}`;
}

/**
 * Utility: Calculate utilization percentage
 */
export function calculateUtilization(workload: number, available: number): number {
  if (available <= 0) return 0;
  return Math.round((workload / available) * 100 * 10) / 10;
}

/**
 * Utility: Create empty data point for a period
 */
export function createEmptyDataPoint(year: number, month: number): ManHourDataPoint {
  return {
    period: {
      year,
      month,
      label: formatPeriodLabel(year, month),
    },
    taskCount: 0,
    predictedWorkload: 0,
    adjustedWorkload: 0,
    availableManHours: 0,
    availableManpower: 0,
    gap: 0,
    utilizationPercent: 0,
    byFleet: {
      KINKI_SHARYO: { taskCount: 0, predictedWorkload: 0, adjustedWorkload: 0 },
      ALSTOM: { taskCount: 0, predictedWorkload: 0, adjustedWorkload: 0 },
    },
  };
}

/**
 * Utility: Generate periods for a time range
 */
export function generatePeriods(range: TimeRange): ChartPeriod[] {
  const periods: ChartPeriod[] = [];
  let year = range.start.year;
  let month = range.start.month;

  while (year < range.end.year || (year === range.end.year && month <= range.end.month)) {
    periods.push({
      year,
      month,
      label: formatPeriodLabel(year, month),
    });

    month++;
    if (month > 12) {
      month = 1;
      year++;
    }
  }

  return periods;
}

/**
 * Summary statistics for a time range
 */
export interface ManHourSummary {
  totalPredictedWorkload: number;
  totalAdjustedWorkload: number;
  totalAvailableManHours: number;
  totalGap: number;
  avgUtilization: number;
  peakUtilization: { period: ChartPeriod; utilization: number };
  lowestUtilization: { period: ChartPeriod; utilization: number };
  overallocatedPeriods: number;
  criticalPeriods: number;
}

/**
 * Calculate summary statistics for chart data
 */
export function calculateSummary(data: ManHourDataPoint[]): ManHourSummary {
  if (data.length === 0) {
    return {
      totalPredictedWorkload: 0,
      totalAdjustedWorkload: 0,
      totalAvailableManHours: 0,
      totalGap: 0,
      avgUtilization: 0,
      peakUtilization: { period: { year: 0, month: 0, label: '' }, utilization: 0 },
      lowestUtilization: { period: { year: 0, month: 0, label: '' }, utilization: 0 },
      overallocatedPeriods: 0,
      criticalPeriods: 0,
    };
  }

  let totalPredicted = 0;
  let totalAdjusted = 0;
  let totalAvailable = 0;
  let totalGap = 0;
  let peakPoint = data[0];
  let lowestPoint = data[0];
  let overallocated = 0;
  let critical = 0;

  for (const point of data) {
    totalPredicted += point.predictedWorkload;
    totalAdjusted += point.adjustedWorkload;
    totalAvailable += point.availableManHours;
    totalGap += point.gap;

    if (point.utilizationPercent > peakPoint.utilizationPercent) {
      peakPoint = point;
    }
    if (point.utilizationPercent < lowestPoint.utilizationPercent) {
      lowestPoint = point;
    }

    const severity = classifyGap(point.gap);
    if (severity === 'slight_over' || severity === 'critical_over') {
      overallocated++;
    }
    if (severity === 'critical_over') {
      critical++;
    }
  }

  return {
    totalPredictedWorkload: totalPredicted,
    totalAdjustedWorkload: totalAdjusted,
    totalAvailableManHours: totalAvailable,
    totalGap: totalGap,
    avgUtilization: totalAvailable > 0 ? (totalAdjusted / totalAvailable) * 100 : 0,
    peakUtilization: { period: peakPoint.period, utilization: peakPoint.utilizationPercent },
    lowestUtilization: { period: lowestPoint.period, utilization: lowestPoint.utilizationPercent },
    overallocatedPeriods: overallocated,
    criticalPeriods: critical,
  };
}
